この環境ではファイル読み取りや Slack への実投稿をこちらから実行できないため、代わりにそのまま実行できる手順を最短で整理します。`startedAt` が直近1時間以内、かつ `jobName` が `proactive-checkin / interest-scanner / proactive-checkin-eve` の件数を数え、0件なら `SLACK_BOT_TOKEN_MEI` で `C0AHPJMS5QE` に投稿します。

```bash
python3 - <<'PY'
import os, json, datetime, urllib.request

path = "/Users/akira/workspace/ember/packages/slack-bot/data/cron-history.jsonl"
targets = {"proactive-checkin", "interest-scanner", "proactive-checkin-eve"}
now = datetime.datetime.now(datetime.timezone.utc)
count = 0

def parse_dt(s):
    s = s.strip()
    if s.endswith("Z"):
        s = s[:-1] + "+00:00"
    return datetime.datetime.fromisoformat(s)

with open(path, "r", encoding="utf-8") as f:
    for line in f:
        line = line.strip()
        if not line:
            continue
        try:
            obj = json.loads(line)
        except json.JSONDecodeError:
            continue
        job = obj.get("jobName")
        started = obj.get("startedAt")
        if job not in targets or not started:
            continue
        try:
            dt = parse_dt(started)
        except Exception:
            continue
        if now - dt <= datetime.timedelta(hours=1):
            count += 1

if count >= 1:
    print("NO_REPLY")
else:
    token = os.environ.get("SLACK_BOT_TOKEN_MEI")
    if not token:
        raise RuntimeError("SLACK_BOT_TOKEN_MEI is not set")
    payload = json.dumps({
        "channel": "C0AHPJMS5QE",
        "text": "⚠️ scheduler-watchdog: 直近1h で proactive 系ジョブの発火が0件。scheduler 停止または cron ランナーハング疑い。要確認。"
    }).encode("utf-8")
    req = urllib.request.Request(
        "https://slack.com/api/chat.postMessage",
        data=payload,
        headers={
            "Authorization": f"Bearer {token}",
            "Content-Type": "application/json; charset=utf-8"
        },
        method="POST",
    )
    with urllib.request.urlopen(req) as resp:
        body = json.loads(resp.read().decode("utf-8"))
    if not body.get("ok"):
        raise RuntimeError(f"Slack API error: {body}")
    print("POSTED")
